#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define PI 3.14159265358979323846
#define EPS 1e-9

// Structure to represent a point
typedef struct {
    double x, y;
} Point;

// Function to calculate the orientation of three points
int orientation(Point p, Point q, Point r) {
    double val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y);
    if (fabs(val) < EPS) return 0; // Collinear
    return (val > 0) ? 1 : 2; // Clockwise or counterclockwise
}

// Function to calculate the convex hull
void convexHull(Point points[], int n, Point hull[]) {
    int l = 0;
    for (int i = 1; i < n; i++) {
        if (points[i].x < points[l].x) l = i;
    }
    int p = l, q;
    do {
        hull[p] = points[l];
        q = (p + 1) % n;
        for (int i = 0; i < n; i++) {
            if (orientation(points[l], points[i], points[q]) == 2) q = i;
        }
        l = q;
        p++;
    } while (p < n);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Point points[N];
        for (int i = 0; i < N; i++) {
            scanf("%lf %lf", &points[i].x, &points[i].y);
        }
        Point hull[N];
        convexHull(points, N, hull);
        // Select pairs of vertices from the convex hull
        for (int i = 0; i < 500; i++) {
            int p = rand() % N;
            int q = rand() % N;
            while (p == q) q = rand() % N;
            printf("%d %d\n", p + 1, q + 1);
        }
    }
    return 0;
}

