import random
import sys

class Point:
    def __init__(self, x, y):
        self.x = x
        self.y = y

def orientation(p, q, r):
    val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y)
    if abs(val) < 1e-9: return 0  # Collinear
    return 1 if val > 0 else 2  # Clockwise or counterclockwise

def convex_hull(points):
    n = len(points)
    l = 0
    for i in range(1, n):
        if points[i].x < points[l].x: l = i
    p = l
    hull = []
    while True:
        hull.append(points[l])
        q = (p + 1) % n
        for i in range(n):
            if orientation(points[l], points[i], points[q]) == 2: q = i
        l = q
        p = (p + 1) % n
        if p == l: break
    return hull

def main():
    T = int(input())
    for _ in range(T):
        N = int(input())
        points = [Point(*map(float, input().split())) for _ in range(N)]
        hull = convex_hull(points)
        # Select pairs of vertices from the convex hull
        for _ in range(500):
            p = random.randint(0, N - 1)
            q = random.randint(0, N - 1)
            while p == q: q = random.randint(0, N - 1)
            print(p + 1, q + 1)
if __name__ == '__main__':
    main()

